from agent import *from models.products import *debug = Truedef run(context, session):    session.browser.agent = "Mozilla/6.0"    session.queue(Request("https://www.ausgolf.com.au/golf-equipment"), process_catlist, {})def process_catlist(data, context, session):    cats = data.xpath("//ul[@id='sidenav']/li/a")    for cat in cats:        name = cat.xpath(".//text()").string()        url = cat.xpath("@href").string()        session.queue(Request(url), process_category, dict(cat=name))        def process_category(data, context, session):    revs = data.xpath("//ul[@id='sidenav']//li//a")    for rev in revs:        title = rev.xpath(".//text()").string()        url = rev.xpath("@href").string()        session.queue(Request(url), process_review, dict(context, title=title, url=url))def process_review(data, context, session):    product = Product()    product.name = context['title']    product.ssid = context['url'].split('/')[-1]    product.category = context['cat']    product.url = context['url']    review = Review()    review.title = context['title']    review.ssid = product.ssid    review.type = 'pro'    review.url = context['url']    excerpt = data.xpath("//div[@class='col-sm-6 col-sm-push-3']//p//text()").string(multiple=True)    if excerpt:        review.properties.append(ReviewProperty(type='excerpt', value=excerpt))            product.reviews.append(review)    session.emit(product)